parameters.query:
SELECT state, created_at
FROM gnote.user_state
WHERE user_id = {{ $json.message.from.id }}
LIMIT 1;

parameters.jsCode:
const input = $input.first().json;

const text = String(
  input.message ||
  input.raw_text ||
  input.text ||
  input.content ||
  ''
).trim();

const lowerText = text.toLowerCase();

const dbState =
  input.state ||
  input.user_state ||
  'idle';

let effectiveState = dbState || 'idle';

const isSearchCommand =
  lowerText === '/search' ||
  lowerText.startsWith('/search ');

const isCancelCommand =
  lowerText === '/cancel' ||
  lowerText === 'cancel';

if (isCancelCommand) {
  effectiveState = 'command_cancel';
} else if (isSearchCommand) {
  effectiveState = 'command_search';
} else if (dbState === 'waiting_search_query') {
  effectiveState = 'waiting_search_query';
} else if (!effectiveState) {
  effectiveState = 'idle';
}

const searchQueryFromCommand = isSearchCommand
  ? text.replace(/^\/search(@\w+)?/i, '').trim()
  : '';

return [
  {
    json: {
      ...input,
      state: dbState,
      effective_state: effectiveState,
      is_search_command: isSearchCommand,
      search_query: searchQueryFromCommand,
      has_search_query: searchQueryFromCommand.length > 0
    }
  }
];

const input = $input.first().json || {};

const callback = input.callback_query;

if (!callback) {
  throw new Error('This node expects callback_query');
}

const data = String(callback.data || '').trim();

const match = data.match(/^download_msg:(\d+)$/);

if (!match) {
  throw new Error(`Invalid download callback data: ${data}`);
}

const messageId = Number(match[1]);

if (!Number.isFinite(messageId) || messageId <= 0) {
  throw new Error(`Invalid message id in callback data: ${data}`);
}

return [
  {
    json: {
      user_id: callback.from.id,
      chat_id: callback.message?.chat?.id || callback.from.id,
      message_id: messageId,
      callback_query_id: callback.id,
      callback_data: data
    }
  }
];

const items = $input.all();

const trigger = $('Telegram Trigger').first().json || {};

const fallbackChatId =
  trigger.callback_query?.message?.chat?.id ||
  trigger.callback_query?.from?.id ||
  trigger.message?.chat?.id ||
  trigger.message?.from?.id ||
  null;

const fallbackCallbackQueryId =
  trigger.callback_query?.id ||
  null;

function clean(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function truncateCaption(text, max = 1024) {
  const value = clean(text);
  if (value.length <= max) return value;
  return value.slice(0, max - 1) + '…';
}

function buildAnswerCallback(callbackQueryId, text = 'Preparing file…') {
  if (!callbackQueryId) return null;

  return {
    json: {
      api_method: 'answerCallbackQuery',
      body: {
        callback_query_id: callbackQueryId,
        text,
        show_alert: false
      }
    }
  };
}

function buildMessage(chatId, text) {
  return {
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: chatId,
        text
      }
    }
  };
}

if (!items.length) {
  const output = [];

  const answer = buildAnswerCallback(
    fallbackCallbackQueryId,
    'File not found'
  );

  if (answer) output.push(answer);

  output.push(
    buildMessage(
      fallbackChatId,
      'File not found or you do not have access ⚠️'
    )
  );

  return output;
}

const data = items[0].json || {};

const chatId =
  data.chat_id ||
  fallbackChatId;

const callbackQueryId =
  data.callback_query_id ||
  fallbackCallbackQueryId;

const output = [];

const answer = buildAnswerCallback(callbackQueryId, 'Preparing download…');

if (answer) {
  output.push(answer);
}

if (!data.found || data.download_status === 'not_found') {
  output.push(
    buildMessage(
      chatId,
      'File not found or you do not have access ⚠️'
    )
  );

  return output;
}

const messageType = clean(data.message_type || 'document').toLowerCase();

const caption = truncateCaption(
  data.caption ||
  data.file_name ||
  data.content ||
  ''
);

if (!data.file_id && messageType !== 'location') {
  output.push(
    buildMessage(
      chatId,
      'This message has no downloadable file ⚠️'
    )
  );

  return output;
}

// Location is not a file, send it as a map link
if (messageType === 'location') {
  const title = data.location_title ? `\n${data.location_title}` : '';
  const address = data.location_address ? `\n${data.location_address}` : '';

  const coords =
    data.latitude !== null &&
    data.latitude !== undefined &&
    data.longitude !== null &&
    data.longitude !== undefined
      ? `\nCoordinates: ${data.latitude}, ${data.longitude}`
      : '';

  const maps = data.maps_url ? `\nGoogle Maps: ${data.maps_url}` : '';

  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: chatId,
        text: `📍 Location${title}${address}${coords}${maps}`.trim(),
        disable_web_page_preview: false
      }
    }
  });

  return output;
}

// Photo
if (messageType === 'photo') {
  const body = {
    chat_id: chatId,
    photo: data.file_id
  };

  if (caption) {
    body.caption = caption;
  }

  output.push({
    json: {
      api_method: 'sendPhoto',
      body
    }
  });

  return output;
}

// Video
if (messageType === 'video') {
  const body = {
    chat_id: chatId,
    video: data.file_id
  };

  if (caption) {
    body.caption = caption;
  }

  output.push({
    json: {
      api_method: 'sendVideo',
      body
    }
  });

  return output;
}

// Telegram circle video / video note
if (messageType === 'video_note') {
  output.push({
    json: {
      api_method: 'sendVideoNote',
      body: {
        chat_id: chatId,
        video_note: data.file_id
      }
    }
  });

  return output;
}

// Voice message
if (messageType === 'voice') {
  const body = {
    chat_id: chatId,
    voice: data.file_id
  };

  if (caption && caption !== '[voice message]') {
    body.caption = caption;
  }

  output.push({
    json: {
      api_method: 'sendVoice',
      body
    }
  });

  return output;
}

// Audio file
if (messageType === 'audio') {
  const body = {
    chat_id: chatId,
    audio: data.file_id
  };

  if (caption) {
    body.caption = caption;
  }

  output.push({
    json: {
      api_method: 'sendAudio',
      body
    }
  });

  return output;
}

// Document / PDF / Word / Excel / unknown file
const body = {
  chat_id: chatId,
  document: data.file_id
};

if (caption) {
  body.caption = caption;
}

output.push({
  json: {
    api_method: 'sendDocument',
    body
  }
});

return output;

