parameters.jsCode:
const input = $input.first().json;

return [
  {
    json: {
      user_id: input.user_id,
      chat_id: input.chat_id,
      text:
`🔎 What do you want to find?

Send:
• 1–2 words for quick search
• longer text for AI semantic search
• voice message
• photo / screenshot
• PDF / document

Examples:
• salary
• NAYA salary
• find the document about my salary from May
• photo with a woman at computer
• screenshot with bank payment`,
      inline_keyboard: [
        [
          {
            text: '❌ Cancel search',
            callback_data: 'action:cancel_pending'
          }
        ]
      ]
    }
  }
];

const stateInput = $input.first().json || {};

// Берем оригинальный Telegram update из Telegram Trigger,
// потому что после get user state в input может остаться только state.
let update = {};

try {
  update = $('Telegram Trigger').first().json || {};
} catch (e) {
  update = {};
}

if (!update.message && !update.edited_message && !update.callback_query) {
  update = stateInput;
}

const message =
  update.message ||
  update.edited_message ||
  stateInput.message ||
  stateInput.edited_message ||
  {};

const from = message.from || {};
const chat = message.chat || {};

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }

  return null;
}

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

function countWords(text) {
  const value = clean(text);

  if (!value) return 0;

  return value
    .split(/\s+/)
    .map(w => w.trim())
    .filter(Boolean)
    .length;
}

const userId =
  stateInput.user_id ||
  update.user_id ||
  from.id ||
  null;

const chatId =
  stateInput.chat_id ||
  update.chat_id ||
  chat.id ||
  userId ||
  null;

if (!userId || !chatId) {
  throw new Error(
    `Cannot detect user_id or chat_id in Prepare search query payload. ` +
    `Input keys: ${Object.keys(stateInput).join(', ')}. ` +
    `Update keys: ${Object.keys(update).join(', ')}`
  );
}

let messageType = 'text';
let fileId = null;
let fileUniqueId = null;
let fileName = null;
let mimeType = null;
let caption = clean(message.caption || '');
let searchQuery = clean(message.text || message.caption || '');

if (message.photo && Array.isArray(message.photo) && message.photo.length) {
  messageType = 'photo';

  const bestPhoto = message.photo[message.photo.length - 1];

  fileId = bestPhoto.file_id;
  fileUniqueId = bestPhoto.file_unique_id;
  fileName = 'photo.jpg';
  mimeType = 'image/jpeg';
  searchQuery = caption;
}

if (message.document) {
  messageType = 'document';
  fileId = message.document.file_id;
  fileUniqueId = message.document.file_unique_id;
  fileName = message.document.file_name || 'document';
  mimeType = message.document.mime_type || 'application/octet-stream';
  searchQuery = caption;
}

if (message.voice) {
  messageType = 'voice';
  fileId = message.voice.file_id;
  fileUniqueId = message.voice.file_unique_id;
  fileName = 'voice.ogg';
  mimeType = message.voice.mime_type || 'audio/ogg';
  searchQuery = caption;
}

if (message.audio) {
  messageType = 'audio';
  fileId = message.audio.file_id;
  fileUniqueId = message.audio.file_unique_id;
  fileName = message.audio.file_name || 'audio';
  mimeType = message.audio.mime_type || 'audio/mpeg';
  searchQuery = caption;
}

if (message.video) {
  messageType = 'video';
  fileId = message.video.file_id;
  fileUniqueId = message.video.file_unique_id;
  fileName = message.video.file_name || 'video.mp4';
  mimeType = message.video.mime_type || 'video/mp4';
  searchQuery = caption;
}

if (message.video_note) {
  messageType = 'video_note';
  fileId = message.video_note.file_id;
  fileUniqueId = message.video_note.file_unique_id;
  fileName = 'video_note.mp4';
  mimeType = 'video/mp4';
  searchQuery = caption;
}

const hasFile = Boolean(fileId);

const queryWordCount = countWords(searchQuery);

const supportedAiMediaTypes = [
  'photo',
  'document',
  'voice',
  'audio',
  'video',
  'video_note'
];

const isMediaQuery =
  hasFile &&
  supportedAiMediaTypes.includes(messageType);

const isLongTextQuery =
  messageType === 'text' &&
  queryWordCount >= 3;

const isShortTextQuery =
  messageType === 'text' &&
  queryWordCount > 0 &&
  queryWordCount <= 2;

const shouldUseAiSearch =
  isMediaQuery ||
  isLongTextQuery;

const searchQueryReady =
  isShortTextQuery ||
  shouldUseAiSearch;

let searchError = null;

if (!searchQueryReady) {
  searchError = 'Please send a text search query, voice message, photo, or document.';
}

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,

      state: stateInput.state || 'waiting_search_query',

      message_id: message.message_id || null,
      message_type: messageType,

      search_query: searchQuery,
      original_search_query: searchQuery,
      query_word_count: queryWordCount,

      file_id: fileId,
      file_unique_id: fileUniqueId,
      file_name: fileName,
      mime_type: mimeType,
      caption,

      has_file: hasFile,
      is_media_query: isMediaQuery,
      is_long_text_query: isLongTextQuery,
      is_short_text_query: isShortTextQuery,

      should_use_ai_search: shouldUseAiSearch,
      should_download_search_file: isMediaQuery,

      search_query_ready: searchQueryReady,
      search_error: searchError,

      telegram_message: message
    }
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      callback_query_id: input.callback_query.id,
      telegram_message_id: input.callback_query.message.message_id
    }
  }
];

