const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      callback_query_id: input.callback_query.id,
      telegram_message_id: input.callback_query.message.message_id
    }
  }
];

const input = $input.first().json || {};

function tryNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

// Try to recover the original Telegram payload/message payload
const messagePayload = tryNodeJson('prepare message payload');
const telegramTrigger = tryNodeJson('Telegram Trigger');
const parseIncoming = tryNodeJson('parse incoming update');

const userId = firstValue(
  input.user_id,
  messagePayload.user_id,
  parseIncoming.user_id,
  telegramTrigger.message?.from?.id,
  telegramTrigger.callback_query?.from?.id,
  input.message?.from?.id,
  input.callback_query?.from?.id
);

const chatId = firstValue(
  input.chat_id,
  messagePayload.chat_id,
  parseIncoming.chat_id,
  telegramTrigger.message?.chat?.id,
  telegramTrigger.callback_query?.message?.chat?.id,
  input.message?.chat?.id,
  input.callback_query?.message?.chat?.id,
  userId
);

const rawText = String(
  input.raw_text ||
  input.text ||
  input.content ||
  input.message_text ||
  input.message?.text ||
  messagePayload.raw_text ||
  messagePayload.text ||
  messagePayload.content ||
  messagePayload.message ||
  telegramTrigger.message?.text ||
  parseIncoming.raw_text ||
  parseIncoming.text ||
  ''
).trim();

const cleanedText = rawText
  .replace(/^\/\w+\s*/i, '')
  .trim();

const extraKeywords = cleanedText
  .split(/[,\n;]+|\s+/)
  .map(v => v.trim())
  .filter(Boolean)
  .filter(v => !['and', 'or', 'и', 'или'].includes(v.toLowerCase()))
  .slice(0, 20);

return [
  {
    json: {
      ...input,
      user_id: userId,
      chat_id: chatId,
      raw_extra_keywords_text: rawText,
      extra_keywords: extraKeywords,
      extra_keywords_text: extraKeywords.join(', ')
    }
  }
];

