const input = $input.first().json || {};
const callback = input.callback_query;

if (!callback) {
  throw new Error('This node expects callback_query');
}

const data = String(callback.data || '');
const match = data.match(/^summary_msg:(\d+)$/);

if (!match) {
  throw new Error(`Unsupported summary callback: ${data}`);
}

return [
  {
    json: {
      user_id: callback.from.id,
      chat_id: callback.message.chat.id,
      callback_query_id: callback.id,
      telegram_message_id: callback.message.message_id,
      message_id: Number(match[1])
    }
  }
];

const input = $input.first().json || {};

function clean(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function short(value, max = 2500) {
  const text = clean(value);
  if (!text) return '';
  return text.length > max ? text.slice(0, max - 3) + '...' : text;
}

if (!input.found) {
  return [
    {
      json: {
        chat_id: input.chat_id,
        callback_query_id: input.callback_query_id,
        text: 'Summary not found ⚠️'
      }
    }
  ];
}

const title =
  input.file_name ||
  input.caption ||
  input.content ||
  'Message';

const summary =
  input.ai_summary ||
  input.ai_content ||
  '';

// Маппинг для красивого и правильного отображения языков
const languageMap = {
  'he': 'Hebrew 🇮🇱',
  'ru': 'Russian 🇷🇺',
  'en': 'English 🇬🇧',
  'hebrew': 'Hebrew 🇮🇱',
  'russian': 'Russian 🇷🇺',
  'english': 'English 🇬🇧'
};

const displayLanguage = languageMap[String(input.ai_language).toLowerCase()] || input.ai_language || 'Unknown';
const category = String(input.ai_category || 'note').toUpperCase();

// Формируем чистый текст БЕЗ блока Keywords
let text = `🧠 *Summary*\n\n*${short(title, 180)}*`;

if (summary) {
  text += `\n\n${short(summary, 2200)}`;
} else {
  text += `\n\nNo AI summary found for this message.`;
}

text += `\n\n*Category:* ${category}`;
text += `\n*Document Language:* ${displayLanguage}`;

return [
  {
    json: {
      chat_id: input.chat_id,
      callback_query_id: input.callback_query_id,
      text
    }
  }
];

