parameters.jsCode:
const input = $input.first().json || {};
const callback = input.callback_query;

if (!callback) {
  throw new Error('This node expects callback_query');
}

const data = String(callback.data || '').trim();

if (data !== 'action:show_pending_ai') {
  throw new Error(`Unsupported pending AI callback: ${data}`);
}

return [
  {
    json: {
      user_id: callback.from.id,
      chat_id: callback.message?.chat?.id || callback.from.id,
      callback_query_id: callback.id,
      telegram_message_id: callback.message?.message_id || null,
      callback_data: data
    }
  }
];

const input = $input.first().json || {};

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

function stripCodeFences(text) {
  return String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseJsonFromText(value) {
  if (!value) return null;

  if (typeof value === 'object' && !Array.isArray(value)) {
    return value;
  }

  const raw = stripCodeFences(String(value));

  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (e) {}
  }

  return null;
}

function toArray(value) {
  if (Array.isArray(value)) {
    return value.map(v => clean(v)).filter(Boolean);
  }

  if (typeof value === 'string') {
    const parsed = parseJsonFromText(value);

    if (Array.isArray(parsed)) {
      return parsed.map(v => clean(v)).filter(Boolean);
    }

    if (parsed && typeof parsed === 'object') {
      if (Array.isArray(parsed.keywords)) {
        return parsed.keywords.map(v => clean(v)).filter(Boolean);
      }

      if (Array.isArray(parsed.ai_keywords)) {
        return parsed.ai_keywords.map(v => clean(v)).filter(Boolean);
      }
    }

    return value
      .split(',')
      .map(v => clean(v))
      .filter(Boolean);
  }

  return [];
}

function uniqueArray(values, limit = 30) {
  const seen = new Set();
  const result = [];

  for (const value of values) {
    const item = clean(value);

    if (!item) continue;

    const key = item.toLowerCase();

    if (seen.has(key)) continue;

    seen.add(key);
    result.push(item);

    if (result.length >= limit) break;
  }

  return result;
}

function truncate(text, max = 1800) {
  const value = clean(text);

  if (value.length <= max) {
    return value;
  }

  return value.slice(0, max - 1) + '…';
}

function normalizeConfidence(value) {
  const number = Number(value);

  if (!Number.isFinite(number)) {
    return null;
  }

  if (number <= 1) {
    return Math.round(number * 100);
  }

  return Math.round(number);
}

function removeTechnicalPrefix(text) {
  let value = clean(text);

  // Убираем типичный мусорный префикс из ai_content:
  // "Message type: photo Summary: ..."
  value = value.replace(/^Source mode:\s*[^]+?Summary:\s*/i, '');
  value = value.replace(/^Message type:\s*[^]+?Summary:\s*/i, '');
  value = value.replace(/^File name:\s*[^]+?Summary:\s*/i, '');
  value = value.replace(/^MIME type:\s*[^]+?Summary:\s*/i, '');

  return clean(value);
}

function extractPayloads(input) {
  const payloads = [];

  const candidates = [
    input.ai_raw_json,
    input.ai_summary,
    input.ai_content,
    input.ai_keywords,
    input.ai_important_details
  ];

  for (const candidate of candidates) {
    const parsed = parseJsonFromText(candidate);

    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      payloads.push(parsed);
    }
  }

  return payloads;
}

function extractSummary(input, payloads) {
  // 1. Сначала ищем summary в распарсенных JSON-объектах
  for (const payload of payloads) {
    if (payload.summary) {
      const nested = parseJsonFromText(payload.summary);

      if (nested && typeof nested === 'object' && nested.summary) {
        return clean(nested.summary);
      }

      const value = removeTechnicalPrefix(payload.summary);

      if (
        value &&
        !value.startsWith('{') &&
        !value.includes('Important details:')
      ) {
        return value;
      }

      if (nested && nested.summary) {
        return clean(nested.summary);
      }
    }

    if (payload.ai_summary) {
      const nested = parseJsonFromText(payload.ai_summary);

      if (nested && typeof nested === 'object' && nested.summary) {
        return clean(nested.summary);
      }

      const value = removeTechnicalPrefix(payload.ai_summary);

      if (
        value &&
        !value.startsWith('{') &&
        !value.includes('Important details:')
      ) {
        return value;
      }
    }
  }

  // 2. Потом пробуем input.ai_summary напрямую
  const directSummaryParsed = parseJsonFromText(input.ai_summary);

  if (directSummaryParsed && directSummaryParsed.summary) {
    return clean(directSummaryParsed.summary);
  }

  const directSummary = removeTechnicalPrefix(input.ai_summary);

  if (
    directSummary &&
    !directSummary.startsWith('{') &&
    !directSummary.includes('Important details:') &&
    !directSummary.includes('Binary source:')
  ) {
    return directSummary;
  }

  // 3. В крайнем случае пробуем вытащить summary из ai_content
  const aiContent = clean(input.ai_content);

  const summaryMatch = aiContent.match(/Summary:\s*(\{[\s\S]*?\})\s*Category:/i);

  if (summaryMatch) {
    const parsed = parseJsonFromText(summaryMatch[1]);

    if (parsed && parsed.summary) {
      return clean(parsed.summary);
    }
  }

  const jsonFromContent = parseJsonFromText(aiContent);

  if (jsonFromContent && jsonFromContent.summary) {
    return clean(jsonFromContent.summary);
  }

  return 'No AI summary available.';
}

function extractCategory(input, payloads) {
  for (const payload of payloads) {
    if (payload.category) return clean(payload.category);
    if (payload.ai_category) return clean(payload.ai_category);
  }

  return clean(input.ai_category || 'unknown');
}

function extractLanguage(input, payloads) {
  for (const payload of payloads) {
    if (payload.language) return clean(payload.language);
    if (payload.detected_language) return clean(payload.detected_language);
    if (payload.ai_language) return clean(payload.ai_language);
  }

  return clean(input.ai_language || 'unknown');
}

function extractConfidence(input, payloads) {
  for (const payload of payloads) {
    if (payload.confidence !== undefined && payload.confidence !== null) {
      return normalizeConfidence(payload.confidence);
    }

    if (payload.ai_confidence !== undefined && payload.ai_confidence !== null) {
      return normalizeConfidence(payload.ai_confidence);
    }
  }

  return normalizeConfidence(input.ai_confidence);
}

function extractKeywords(input, payloads) {
  const values = [];

  for (const payload of payloads) {
    values.push(...toArray(payload.keywords));
    values.push(...toArray(payload.search_keywords));
    values.push(...toArray(payload.ai_keywords));
  }

  values.push(...toArray(input.ai_keywords));

  const technicalNoise = new Set([
    'photo',
    'photo.jpg',
    'image/jpeg',
    'image/png',
    'image/webp',
    'image',
    'picture',
    'jpg',
    'jpeg',
    'png',
    'summary'
  ]);

  const unique = uniqueArray(values, 30);

  // Оставляем технические слова только если вообще нет нормальных keywords
  const normal = unique.filter(k => !technicalNoise.has(k.toLowerCase()));

  if (normal.length >= 4) {
    return uniqueArray(normal, 20);
  }

  return unique.slice(0, 20);
}

const chatId = input.chat_id;
const callbackQueryId = input.callback_query_id;

const output = [];

if (callbackQueryId) {
  output.push({
    json: {
      api_method: 'answerCallbackQuery',
      body: {
        callback_query_id: callbackQueryId,
        text: 'AI details',
        show_alert: false
      }
    }
  });
}

if (!input.pending_found) {
  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: chatId,
        text: 'No pending message found ⚠️'
      }
    }
  });

  return output;
}

if (!input.ai_found) {
  output.push({
    json: {
      api_method: 'sendMessage',
      body: {
        chat_id: chatId,
        text: 'AI details are not available for this message yet ⚠️'
      }
    }
  });

  return output;
}

const payloads = extractPayloads(input);

const summary = truncate(
  extractSummary(input, payloads),
  1800
);

const category = extractCategory(input, payloads);
const language = extractLanguage(input, payloads);
const confidence = extractConfidence(input, payloads);
const keywords = extractKeywords(input, payloads);

const lines = [
  '🧠 AI summary',
  '',
  'Summary:',
  summary,
  '',
  `Category: ${category || 'unknown'}`,
  `Language: ${language || 'unknown'}`
];

if (confidence !== null) {
  lines.push(`Confidence: ${confidence}%`);
}

if (keywords.length) {
  lines.push('');
  lines.push('Keywords:');
  lines.push(keywords.join(', '));
}

output.push({
  json: {
    api_method: 'sendMessage',
    body: {
      chat_id: chatId,
      text: lines.join('\n'),
      disable_web_page_preview: true
    }
  }
});

return output;

const currentItem = $input.first();
const current = currentItem.json || {};

let original = {};

try {
  original = $('Prepare search query payload').first().json || {};
} catch (e) {
  original = {};
}

const item = {
  ...original,
  ...current,

  user_id: original.user_id || current.user_id,
  chat_id: original.chat_id || current.chat_id,

  message_type: original.message_type || current.message_type || 'text',

  search_query: original.search_query || current.search_query || '',
  original_search_query: original.original_search_query || current.original_search_query || '',

  file_id: original.file_id || current.file_id,
  file_unique_id: original.file_unique_id || current.file_unique_id,
  file_name: original.file_name || current.file_name,
  mime_type: original.mime_type || current.mime_type,
  caption: original.caption || current.caption,

  telegram_file_path:
    current.result?.file_path ||
    current.file_path ||
    original.telegram_file_path ||
    current.telegram_file_path
};

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return fallback;
  return String(value);
}

function getExtension(fileName) {
  const match = safeString(fileName).toLowerCase().match(/\.([a-z0-9]+)$/);
  return match ? match[1] : '';
}

function normalizeMimeType(mimeType, ext, messageType) {
  const mt = safeString(mimeType).toLowerCase();

  if (mt && mt !== 'application/octet-stream') {
    return mt;
  }

  if (messageType === 'photo') {
    if (ext === 'png') return 'image/png';
    if (ext === 'webp') return 'image/webp';
    if (ext === 'heic') return 'image/heic';
    return 'image/jpeg';
  }

  if (messageType === 'voice') return 'audio/ogg';
  if (messageType === 'audio') return 'audio/mpeg';
  if (messageType === 'video' || messageType === 'video_note') return 'video/mp4';

  if (ext === 'jpg' || ext === 'jpeg') return 'image/jpeg';
  if (ext === 'png') return 'image/png';
  if (ext === 'webp') return 'image/webp';
  if (ext === 'heic') return 'image/heic';

  if (ext === 'pdf') return 'application/pdf';
  if (ext === 'json') return 'application/json';
  if (ext === 'xml') return 'application/xml';
  if (ext === 'txt') return 'text/plain';
  if (ext === 'csv') return 'text/csv';

  return mimeType || 'application/octet-stream';
}

async function findBinaryData() {
  const binary = currentItem.binary || {};
  const keys = Object.keys(binary);

  if (!keys.length) {
    return null;
  }

  const propertyName = keys.includes('data') ? 'data' : keys[0];
  const meta = binary[propertyName];

  if (!meta) {
    return null;
  }

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(0, propertyName);

    return {
      data: buffer.toString('base64'),
      mimeType: meta.mimeType || meta.mime_type || null,
      fileName: meta.fileName || meta.file_name || null,
      fileSize: buffer.length,
      propertyName,
      source: 'binary_buffer_from_n8n'
    };
  } catch (error) {
    return {
      data: null,
      mimeType: meta.mimeType || meta.mime_type || null,
      fileName: meta.fileName || meta.file_name || null,
      fileSize: null,
      propertyName,
      source: 'binary_buffer_read_failed',
      error: error.message
    };
  }
}

const userId = item.user_id;
const chatId = item.chat_id;

const messageType = clean(item.message_type || 'text').toLowerCase();

let fileName = clean(
  item.file_name ||
  item.telegram_file_path ||
  (
    messageType === 'photo'
      ? 'photo.jpg'
      : messageType === 'voice'
        ? 'voice.ogg'
        : messageType === 'video_note'
          ? 'video_note.mp4'
          : 'file'
  )
);

const ext = getExtension(fileName);

let mimeType = normalizeMimeType(
  item.mime_type || 'application/octet-stream',
  ext,
  messageType
);

const binaryData = await findBinaryData();

if (binaryData?.mimeType) {
  mimeType = normalizeMimeType(binaryData.mimeType, ext, messageType);
}

const originalSearchQuery = clean(item.original_search_query || item.search_query || '');
const caption = clean(item.caption || '');

const isImage =
  messageType === 'photo' ||
  mimeType.startsWith('image/') ||
  ['jpg', 'jpeg', 'png', 'webp', 'heic'].includes(ext);

const isAudio =
  messageType === 'voice' ||
  messageType === 'audio' ||
  mimeType.startsWith('audio/');

const isVideo =
  messageType === 'video' ||
  messageType === 'video_note' ||
  mimeType.startsWith('video/');

const isDocument =
  messageType === 'document' ||
  mimeType.includes('pdf') ||
  mimeType.includes('text') ||
  mimeType.includes('json') ||
  mimeType.includes('xml') ||
  mimeType.includes('word') ||
  mimeType.includes('officedocument');

const supportedInlineMimeTypes = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/heic',

  'audio/ogg',
  'audio/mpeg',
  'audio/mp3',
  'audio/wav',
  'audio/webm',

  'video/mp4',
  'video/webm',

  'application/pdf',
  'text/plain',
  'text/csv',
  'application/json',
  'application/xml'
];

const hasInlineFile =
  Boolean(binaryData?.data) &&
  supportedInlineMimeTypes.includes(mimeType);

const prompt = `
You prepare a semantic search query for a personal memory bot called Memoraq.

The user sent a search request. It may be:
- a long free-form text query
- a voice/audio query
- an image/screenshot used as a search example
- a document/file used as a search example

Your task:
Extract the user's real search intent and produce a concise set of keywords to search saved messages and files.

Important:
- Return only valid JSON.
- Do not include markdown.
- Do not include code fences.
- Do not answer the user's question.
- Do not summarize saved database content.
- Only transform the current search request into a better search query.
- Prefer practical searchable keywords over generic words.
- For images, describe visible objects/text as search keywords.
- For documents/screenshots, extract visible topic, document type, key entities, and language.
- For voice/audio, transcribe the intent and produce search keywords.
- Keep the result focused. Avoid too many generic words.

Telegram search request metadata:
- Message type: ${messageType}
- Original text query: ${originalSearchQuery || 'none'}
- Caption: ${caption || 'none'}
- File name: ${fileName || 'none'}
- MIME type: ${mimeType || 'unknown'}
- File binary provided: ${hasInlineFile ? 'yes' : 'no'}
- Binary source: ${binaryData?.source || 'none'}
- Binary size: ${binaryData?.fileSize || 'unknown'}

Required JSON format:
{
  "search_query": "short natural-language query for searching saved items",
  "language": "detected language or unknown",
  "intent": "what the user wants to find",
  "keywords": ["keyword1", "keyword2", "keyword3"],
  "synonyms": ["synonym1", "synonym2"],
  "entities": ["entity1", "entity2"],
  "content_types": ["photo", "document", "voice", "text"],
  "confidence": 0.5
}
`.trim();

const parts = [
  {
    text: prompt
  }
];

if (hasInlineFile) {
  parts.push({
    inline_data: {
      mime_type: mimeType,
