function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

function stripCodeFences(text) {
  return String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseJsonFromText(text) {
  const raw = stripCodeFences(text);

  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const match = raw.match(/\{[\s\S]*\}/);

  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (e) {}
  }

  return null;
}

function toArray(value) {
  if (Array.isArray(value)) {
    return value.map(v => clean(v)).filter(Boolean);
  }

  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);

      if (Array.isArray(parsed)) {
        return parsed.map(v => clean(v)).filter(Boolean);
      }
    } catch (e) {}

    return value
      .split(',')
      .map(v => clean(v))
      .filter(Boolean);
  }

  return [];
}

function uniqueArray(values, limit = 40) {
  const seen = new Set();
  const result = [];

  for (const value of values) {
    const item = clean(value);

    if (!item) continue;

    const key = item.toLowerCase();

    if (seen.has(key)) continue;

    seen.add(key);
    result.push(item);

    if (result.length >= limit) break;
  }

  return result;
}

function extractGeminiText(response) {
  return (
    response.candidates?.[0]?.content?.parts
      ?.map(part => part.text || '')
      .join('\n')
      .trim() ||
    response.text ||
    response.ai_raw_text ||
    ''
  );
}

function detectLanguage(text, fallback = 'unknown') {
  const str = String(text || '').trim();
  const lower = str.toLowerCase();

  if (!lower) return fallback || 'unknown';

  if (/[\u0590-\u05FF]/.test(str)) return 'hebrew';
  if (/[\u0600-\u06FF]/.test(str)) return 'arabic';

  if (/[іїєґІЇЄҐ]/.test(str)) return 'ukrainian';
  if (/[\u0400-\u04FF]/.test(str)) return 'russian';

  if (/[\u0370-\u03FF]/.test(str)) return 'greek';

  if (/[äöüß]/i.test(str)) return 'german';
  if (/[àâçéèêëîïôùûüÿœæ]/i.test(str)) return 'french';
  if (/[ñ¿¡]/i.test(str)) return 'spanish';
  if (/[ãõ]/i.test(str)) return 'portuguese';
  if (/[ąćęłńóśźż]/i.test(str)) return 'polish';
  if (/[čďěňřšťůž]/i.test(str)) return 'czech';
  if (/[ăâîșț]/i.test(str)) return 'romanian';
  if (/[æøå]/i.test(str)) return 'norwegian/danish';
  if (/[åäö]/i.test(str)) return 'swedish/finnish';

  if (/[a-z]/i.test(str)) return 'english';

  return fallback || 'unknown';
}

