};

function normalizeTerm(value) {
  let term = clean(value)
    .replace(/[^\p{L}\p{N}\s._-]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  const lower = term.toLowerCase();

  if (NORMALIZE_MAP[lower]) {
    return NORMALIZE_MAP[lower];
  }

  return term;
}

function splitToTerms(value) {
  return normalizeTerm(value)
    .split(/\s+/)
    .map(v => normalizeTerm(v))
    .filter(Boolean);
}

function isNoiseTerm(value) {
  const term = normalizeTerm(value);
  const lower = term.toLowerCase();

  if (!term) return true;
  if (NOISE_WORDS.has(lower)) return true;
  if (term.length < 2) return true;

  return false;
}

function cleanPhrase(value) {
  const terms = splitToTerms(value)
    .filter(term => !isNoiseTerm(term));

  return uniqueArray(terms, 12).join(' ');
}

function isUsefulPhrase(value) {
  const phrase = cleanPhrase(value);

  if (!phrase) return false;

  const terms = phrase.split(/\s+/).filter(Boolean);

  if (terms.length === 0) return false;

  // One strong word is enough.
  if (terms.length === 1) {
    const t = terms[0].toLowerCase();

    if (['resume', 'cv', 'performance', 'engineer', 'engineering'].includes(t)) {
      return true;
    }

    return terms[0].length >= 4;
  }

  return true;
}

function cleanKeywordList(values, limit = 30) {
  const result = [];

  for (const value of values) {
    const raw = normalizeTerm(value);
    if (!raw) continue;

    const lower = raw.toLowerCase();

    if (NORMALIZE_MAP[lower]) {
      result.push(NORMALIZE_MAP[lower]);
      continue;
    }

    // Keep useful multi-word phrases, but remove noise inside them.
    if (raw.includes(' ')) {
      const phrase = cleanPhrase(raw);

      if (phrase && isUsefulPhrase(phrase)) {
        result.push(phrase);
      }

      continue;
    }

    if (!isNoiseTerm(raw)) {
      result.push(raw);
    }
  }

  return uniqueArray(result, limit);
}

function fallbackKeywordsFromText(text, source) {
  const values = [];

  const base = clean(text);

  if (base) {
    values.push(...splitToTerms(base));
