const input = $input.first().json || {};

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

let searchSessionId = firstValue(
  input.search_session_id,
  input.callback_search_session_id,
  input.session_id
);

let userId = firstValue(
  input.user_id,
  input.message?.from?.id,
  input.callback_query?.from?.id
);

let chatId = firstValue(
  input.chat_id,
  input.message?.chat?.id,
