parameters.query:
-- 1. Cascadingly delete all user messages from the main storage table
DELETE FROM gnote.messages 
WHERE user_id = {{ $json.message.from.id }}::BIGINT;

-- 2. Clear the temporary table holding messages awaiting user confirmation
DELETE FROM gnote.pending_messages 
WHERE user_id = {{ $json.message.from.id }}::BIGINT;

-- 3. Clear the history of search sessions to reset the interface results
DELETE FROM gnote.search_sessions 
WHERE user_id = {{ $json.message.from.id }}::BIGINT;

-- 4. Reset the dialogue state machine back to the initial 'idle' status
UPDATE gnote.user_state 
SET state = 'idle', search_query = NULL, updated_at = NOW()
WHERE user_id = {{ $json.message.from.id }}::BIGINT;

-- 5. Hard reset the cumulative message counter inside the user profile row
UPDATE gnote.users 
SET all_messages = 0, last_visit = NOW()
WHERE id = {{ $json.message.from.id }}::BIGINT;

-- 6. Explicitly return chat_id for the subsequent Telegram notification node in n8n
SELECT {{ $json.message.chat.id }}::BIGINT AS chat_id;

