parameters.jsCode:
const stats = $input.first().json || {};

const total = Number(stats.real_total || 0);

let text = `📊 **Memoraq Vault Statistics**\n\n`;

if (total === 0) {
  text += `Your digital brain is completely empty.\nSave some thoughts, links, photos, or voice notes to see your stats metrics here! 🧠`;
} else {
  text += `🗂 Total entries: **${total}**\n`;
  text += `───────────────\n`;
  text += `💬 Text notes: **${stats.total_texts || 0}**\n`;
  text += `🖼️ Photographs: **${stats.total_photos || 0}**\n`;
  text += `🎙️ Voice recordings: **${stats.total_voices || 0}**\n`;
  text += `🎬 Videos & notes: **${Number(stats.total_videos || 0) + Number(stats.total_video_notes || 0)}**\n`;
  text += `📍 Saved locations: **${stats.total_locations || 0}**\n`;
  text += `📄 Total documents: **${stats.total_documents || 0}**\n`;

  // Показываем подкатегории только если у пользователя есть файлы типа 'document'
  if (Number(stats.total_documents) > 0) {
    text += `   ├── 📕 PDF Books/Docs: **${stats.docs_pdf || 0}**\n`;
    text += `   ├── 📘 Word/Text files: **${stats.docs_text_files || 0}**\n`;
    text += `   └── 📗 Tables/Excel/CSV: **${stats.docs_spreadsheets || 0}**\n`;
  }
}

return [
  {
    json: {
      chat_id: stats.chat_id,
      text: text
    }
  }
];
